package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import lombok.AllArgsConstructor;
import lombok.Builder;

import java.util.Collection;

@AllArgsConstructor
@Builder
public class BerekenWerkbonusGepensioneerd extends AbstractRekenCommand {

    private final WerkbonusGepensioneerdOpdracht checkOpdracht;
    private final WerkbonusGepensioneerdOpper checkOpper;
    private final WerkbonusGepensioneerdUitbreidingOpdrachtNodig controle;

    public BerekenWerkbonusGepensioneerd(ConstantManager constantManager) {
        checkOpdracht = new WerkbonusGepensioneerdOpdracht();
        checkOpper = new WerkbonusGepensioneerdOpper(constantManager);
        controle = new WerkbonusGepensioneerdUitbreidingOpdrachtNodig(checkOpdracht, checkOpper);
    }

    @Override
    protected boolean execute(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        if (WerkbonusGepensioneerdActief.isActief(rekenTijd)) {
            Persoon persoon = context.getUnchecked(RekenChainKey.PERSOON_KEY);
            RegulManager regulManager = context.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);

            for (Opdracht opdracht : persoon.getOpdrachten()) {
                RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
                controle.check(opdrachtContext, opdracht, regulManager);
                berekenWerkbonusGepensioneerdOpdracht(opdrachtContext, opdracht, regulManager, rekenTijd);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenWerkbonusGepensioneerdOpdracht(RekenContext opdrachtContext, Opdracht opdracht, RegulManager regulManager, RekenTijd rekenTijd) {
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        if (checkOpdracht.komtInAanMerking(opdrachtContext, opdracht)) {
            for (Opper opper : opdracht.getOpperSlices()) {
                berekenWerkbonusGepensioneerdOpper(opper, manager, regulManager, rekenTijd);
            }
        }
    }

    private void berekenWerkbonusGepensioneerdOpper(Opper opper, LoonElementManager manager, RegulManager regulManager, RekenTijd rekenTijd) {
        checkOpper.checkWerkbonusHerstructurering(opper, regulManager);
        if (checkOpper.komtInAanMerking(opper, rekenTijd)) {
            Collection<LoonElement> elementen = manager.getOpperElementen(opper);
            elementen.forEach(this::berekenWerkbonusGepensioneerdLoonElement);
        }
    }

    private void berekenWerkbonusGepensioneerdLoonElement(LoonElement element) {
        Money bijdrage = element.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
        bijdrage = bijdrage.add(element.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY));
        Money verminderingLageLonen = element.getPropertyMoney(RekenRszKey.WERKBONUS_LAGE_LONEN_KEY);
        Money verminderingHeelLageLonen = element.getPropertyMoney(RekenRszKey.WERKBONUS_HEEL_LAGE_LONEN_KEY);
        Money werkbonusGepensioneerd = bijdrage.subtract(verminderingLageLonen).subtract(verminderingHeelLageLonen);
        if (werkbonusGepensioneerd.signum() != 0) {
            element.putProperty(RekenRszKey.WERKBONUS_GEPENSIONEERD_KEY, werkbonusGepensioneerd);
        }
    }


}
